// SPDX-License-Identifier: ISC
//! Replay of frozen RPC dispatch vectors generated by an in-package
//! dump test driving dcrd's own processRequest end-to-end at
//! release-v2.1.5: 19 cases across successful dispatches (with
//! float, string, and null ids and both JSON-RPC versions including
//! the unknown-version fallback), the method-not-found, wallet, and
//! unimplemented classifications, parameter parse failures surfaced
//! as failed-to-parse errors, handler errors, the limited-user gate,
//! the malformed empty-method reply, notification suppression, and
//! the help handler's usage overview, per-method help, and
//! unknown-method error.  Each reply is compared byte for byte.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use dcroxide_chaincfg::mainnet_params;
use dcroxide_chainhash::Hash;
use dcroxide_dcrjson::RpcId;
use dcroxide_rpc::dispatch::process_request;
use dcroxide_rpc::helpers::NoInterfaces;
use dcroxide_rpc::server::{Config, RpcBestState, RpcChain, RpcSubsidyParams, Server};
use dcroxide_standalone::SubsidyCache;
use dcroxide_wire::{BlockHeader, MsgBlock, PROTOCOL_VERSION};

const VECTORS: &str = include_str!("data/rpchandlers12_vectors.txt");

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

fn utf8(hex: &str) -> String {
    String::from_utf8(unhex(hex)).unwrap()
}

/// The scripted chain over the block 432,100 best state.
struct MockChain12 {
    header: BlockHeader,
    block_hash: Result<(), String>,
}

impl RpcChain for MockChain12 {
    fn best_snapshot(&mut self) -> RpcBestState {
        RpcBestState {
            hash: self.header.block_hash(),
            prev_hash: self.header.prev_block,
            height: 432100,
            bits: self.header.bits,
            next_stake_diff: 14428162590,
            total_subsidy: 1122503888072909,
            block_size: u64::from(self.header.size),
            num_txns: 7,
        }
    }
    fn block_hash_by_height(&mut self, _height: i64) -> Result<Hash, String> {
        self.block_hash.clone().map(|()| self.header.block_hash())
    }
}

#[test]
fn dispatch_core_matches_dcrd() {
    let params = mainnet_params();

    let header = include_str!("data/rpchandlers8_vectors.txt")
        .lines()
        .find_map(|line| {
            let f: Vec<&str> = line.split('|').collect();
            (f[0] == "blk").then(|| MsgBlock::from_bytes(&unhex(f[1])).unwrap().0.header)
        })
        .expect("block fixture");

    let lines: Vec<&str> = VECTORS
        .lines()
        .filter(|l| l.starts_with("case|") || l.starts_with("result|"))
        .collect();
    let mut cases = 0;
    let mut i = 0;
    while i < lines.len() {
        let case: Vec<&str> = lines[i].split('|').collect();
        let result: Vec<&str> = lines[i + 1].split('|').collect();
        assert_eq!(case[0], "case");
        assert_eq!(result[0], "result");
        i += 2;
        cases += 1;

        let name = case[2];
        let jsonrpc = case[3];
        let method_name = case[4];
        let id = match case[5] {
            "NULL" => RpcId::Null,
            tag => match tag.split_once(':').unwrap() {
                ("F", v) => RpcId::Float(v.parse().unwrap()),
                ("S", v) => RpcId::Str(v.to_string()),
                other => panic!("unknown id tag {other:?}"),
            },
        };
        let params_joined = utf8(case[6]);
        let raw_params: Vec<&str> = if params_joined.is_empty() {
            Vec::new()
        } else {
            params_joined.split('\x1f').collect()
        };
        let is_admin = case[7] == "true";
        let block_hash = match case[8].strip_prefix("ERR:") {
            Some(err) => Err(err.to_string()),
            None => Ok(()),
        };

        let chain = MockChain12 { header, block_hash };
        let mut server = Server::new(Config {
            chain,
            chain_params: params.clone(),
            subsidy_cache: SubsidyCache::new(RpcSubsidyParams(params.clone())),
            min_relay_tx_fee: 10000,
            max_protocol_version: PROTOCOL_VERSION,
            sync_mgr: Box::new(()),
            conn_mgr: Box::new(()),
            tx_mempooler: Box::new(()),
            clock: Box::new(()),
            interfaces: Box::new(NoInterfaces),
            rand_u64: Box::new(|| 0),
            tx_indexer: None,
            db: Box::new(()),
            filterer_v2: Box::new(()),
            exists_addresser: None,
            log_manager: Box::new(()),
            fee_estimator: Box::new(()),
            block_templater: None,
            sanity_checker: Box::new(()),
            time_source: Box::new(()),
            proxy: String::new(),
            test_net: false,
            runtime_version: String::new(),
            cpu_miner: Box::new(()),
            mix_pooler: Box::new(()),
            profiler_mgr: Box::new(()),
            addr_manager: Box::new(()),
            mining_addrs: Vec::new(),
            user_agent_version: String::new(),
            net_info: Vec::new(),
            services: 0,
            request_shutdown: Box::new(|| {}),
            allow_unsynced_mining: false,
        });

        let reply = process_request(
            &mut server,
            jsonrpc,
            method_name,
            &raw_params,
            &id,
            is_admin,
        );
        match result[2] {
            "none" => assert!(reply.is_none(), "{name}: expected no reply, got {reply:?}"),
            "reply" => {
                let got = reply.unwrap_or_else(|| panic!("{name}: expected a reply"));
                assert_eq!(got, utf8(result[3]), "{name}: reply");
            }
            other => panic!("unknown result kind {other}"),
        }
    }
    assert_eq!(cases, 19, "unexpected case count");
}
